#include <stdio.h>

void selectionSort(int arr[], int n) {
    for (int i = 0; i < n - 1; i++) {
        int minIdx = i;
        for (int j = i + 1; j < n; j++) {
            if (arr[j] < arr[minIdx]) {
                minIdx = j;
            }
        }
        int temp = arr[minIdx];
        arr[minIdx] = arr[i];
        arr[i] = temp;
    }
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int arr[1000]; // N <= 1000
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        selectionSort(arr, N);
        for (int i = 0; i < N; i++) {
            printf("%d", arr[i]);
            if (i + 1 < N) printf(" ");
        }
        printf("\n");
    }
    return 0;
}

